  ('elementary-814ced5a-moex-00418', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '關於權威控制之敘述，下列何者正確？', '["可控制檢索款目的一致性，並建立款目的參照關係", "由權威單位所編的書目紀錄", "由中央主管機關所做的控制工作", "是最好的書目資料"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "40fc77b37f2d", "answer_pdf_sha1": "de904699258a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00419', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '關於MARC21機讀格式之敘述，下列何者錯誤？', '["MARC21是由美國、加拿大、英國等合作推動的MARC調合計畫而來，取名MARC21是寓意其將成 為21世紀之通用格式", "為了讓MARC與圖書館以外的世界接軌，國會圖書館嘗試將MARC格式改以網路通用的XML標誌語 言表示，發展出MARCXML", "主張放棄MARC的聲音始終存在，原因就在MARC是封閉系統，且欄位內容從未更新", "MARC21主要應用於圖書館社群，但它也可與其他詮釋資料格式對映(mapping)，像國會圖書館就已開 發多種MARC21與其他詮釋資料的對映表"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "40fc77b37f2d", "answer_pdf_sha1": "de904699258a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00420', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '關於MARC21的書目格式段意義之說明，下列何者錯誤？', '["2XX題名、版本、出版段", "3XX稽核等資料段", "4XX集叢及附加集叢段", "5XX附註段"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "40fc77b37f2d", "answer_pdf_sha1": "de904699258a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00421', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', 'MARC21中的490為集叢項，下列有關該欄之著錄敘述何者正確？', '["該項為不可重複，若著錄資料記載多個集叢資訊，應著錄於8xx段", "該欄之分欄a，用以著錄集叢題名", "該欄之分欄n，用以著錄集叢號", "該欄指標1空格代表集叢不被檢索，指標2著錄1代表集叢被檢索"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "40fc77b37f2d", "answer_pdf_sha1": "de904699258a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
